-    .filter((s: any) => !options.agent || s.agent === options.agent)
-    .map((s: any) => s.path)
-    .slice(0, options.maxSessions || 20);
+  const limit = options.maxSessions ?? 20;
+  return unprocessed.map((s) => s.path).slice(0, limit);
